    override fun dispatchYield(context: CoroutineContext, block: Runnable) {
        // When yielding, check if there are delayed tasks ready to execute
        // and process them first before adding the yielding continuation to the queue.
        // This ensures that yield() actually yields to other coroutines that are ready to run.
        val delayed = _delayed.value
        if (delayed != null && !delayed.isEmpty) {
            val now = nanoTime()
            while (true) {
                // Move ready delayed tasks to the main queue
                delayed.removeFirstIf {
                    if (it.timeToExecute(now)) {
                        enqueueImpl(it)
                    } else
                        false
                } ?: break
            }
        }
        // Now enqueue the yielding continuation
        enqueue(block)
    }

    open fun enqueue(task: Runnable) {
        if (enqueueImpl(task)) {
            // todo: we should unpark only when this delayed task became first in the queue
            unpark()
        } else {
            DefaultExecutor.enqueue(task)
        }
    }"}

{"file_path": "/project/test_yield_fix.kt", "content": "import kotlinx.coroutines.*
import kotlin.test.*

fun main() {
    testYieldWithDelayedTask()
}

fun testYieldWithDelayedTask() {
    val results = mutableListOf<String>()
    runBlocking {
        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            results.add("first")
        }
        Thread.sleep(1000)
        yield()
        results.add("second")
    }

    println("Results: $results")
    assertEquals(listOf("first", "second"), results, "yield() should yield to the delayed task")
    println("Test passed!")
}"}

